import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.VxKNwi4m.js";const g=JSON.parse('{"title":"문서","description":"","frontmatter":{},"headers":[],"relativePath":"work-manage/docs.md","filePath":"work-manage/docs.md","lastUpdated":1782969549000}'),l={name:"work-manage/docs.md"};function s(i,a,n,d,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="문서" tabindex="-1">문서 <a class="header-anchor" href="#문서" aria-label="Permalink to &quot;문서&quot;">​</a></h1><p>프로젝트 수행 과정에서 생성되는 각종 파일을 체계적으로 보관하고 관리하는 <strong>문서</strong> 페이지에 대한 사용자 가이드입니다.</p><h2 id="_1-화면-개요" tabindex="-1">1. 화면 개요 <a class="header-anchor" href="#_1-화면-개요" aria-label="Permalink to &quot;1. 화면 개요&quot;">​</a></h2><p>문서 화면은 프로젝트 관련 산출물, 참고 자료, 소송 관련 기록 등을 유형별로 분류하여 저장합니다. 강력한 필터링 기능을 통해 방대한 문서 중 필요한 파일을 신속하게 찾을 수 있도록 지원합니다.</p><h2 id="_2-주요-기능-안내" tabindex="-1">2. 주요 기능 안내 <a class="header-anchor" href="#_2-주요-기능-안내" aria-label="Permalink to &quot;2. 주요 기능 안내&quot;">​</a></h2><h3 id="📂-문서-유형-분류-tabs" tabindex="-1">📂 문서 유형 분류 (Tabs) <a class="header-anchor" href="#📂-문서-유형-분류-tabs" aria-label="Permalink to &quot;📂 문서 유형 분류 (Tabs)&quot;">​</a></h3><p>문서의 성격에 따라 두 가지 주요 탭으로 구분되어 관리됩니다.</p><ul><li><strong>일반문서</strong>: 프로젝트 일반 산출물, 기획서, 보고서 등 보편적인 문서 자료를 관리합니다.</li><li><strong>소송기록</strong>: 법적 분쟁이나 소송 관련 사건과 연계된 기록물들을 별도로 관리하며, 관련 사건(Suitcase) 정보를 연결할 수 있습니다.</li></ul><h3 id="🔍-카테고리-필터링-및-검색" tabindex="-1">🔍 카테고리 필터링 및 검색 <a class="header-anchor" href="#🔍-카테고리-필터링-및-검색" aria-label="Permalink to &quot;🔍 카테고리 필터링 및 검색&quot;">​</a></h3><ul><li><strong>카테고리 선택</strong>: 각 문서 유형별로 정의된 카테고리(예: 기획, 예산, 도면 등)를 클릭하여 관련 문서만 즉시 모아볼 수 있습니다.</li><li><strong>통합 검색</strong>: 문서 제목이나 내용을 검색하여 원하는 자료를 빠르게 식별합니다.</li></ul><h3 id="📤-문서-등록-및-편집" tabindex="-1">📤 문서 등록 및 편집 <a class="header-anchor" href="#📤-문서-등록-및-편집" aria-label="Permalink to &quot;📤 문서 등록 및 편집&quot;">​</a></h3><ul><li><strong>새 문서 추가</strong> (<i class="mdi mdi-plus-circle text-success"></i>): 제목, 카테고리, 설명 작성 및 실제 파일을 업로드하여 문서를 등록합니다.</li><li><strong>문서 수정</strong>: 등록된 문서의 정보를 변경하거나 첨부 파일을 교체할 수 있습니다.</li><li><strong>마크다운 지원</strong>: 문서에 대한 상세 설명을 작성할 때 마크다운 문법을 사용하여 풍부한 서식으로 내용을 정리할 수 있습니다.</li></ul><h3 id="📈-정보-확인-및-이력" tabindex="-1">📈 정보 확인 및 이력 <a class="header-anchor" href="#📈-정보-확인-및-이력" aria-label="Permalink to &quot;📈 정보 확인 및 이력&quot;">​</a></h3><ul><li><strong>조회수 트래킹</strong>: 사용자들이 문서를 열람할 때마다 조회수가 자동으로 카운트되어, 자료의 활용도를 파악할 수 있습니다.</li><li><strong>최신순 정렬</strong>: 기본적으로 가장 최근에 등록된 문서가 상단에 노출되어 최신 정보를 우선적으로 확인할 수 있습니다.</li></ul><h2 id="_3-이용-팁" tabindex="-1">3. 이용 팁 <a class="header-anchor" href="#_3-이용-팁" aria-label="Permalink to &quot;3. 이용 팁&quot;">​</a></h2><ul><li><strong>사건 연계</strong>: 소송기록 작성 시 관련 사건 정보를 연결하면, 문서 상세 보기에서 해당 사건의 개요와 문서를 유기적으로 파악할 수 있습니다.</li><li><strong>상세 내용 활용</strong>: 단순히 파일만 올리기보다 마크다운 설명을 활용해 문서의 핵심 요약이나 활용 주의사항을 기재하면 팀원들에게 더 큰 도움이 됩니다.</li><li><strong>조회수 활용</strong>: 조회수가 높은 문서는 팀 내에서 자주 참조되는 중요 문서일 가능성이 높으므로 업무 인수인계 시 참고하세요.</li></ul>',16)])])}const _=t(l,[["render",s]]);export{g as __pageData,_ as default};
